import React from 'react';
import { Table, Button } from 'antd';
import { containerConstantsService } from '../../../utils/containerconstants/ContainerConstants';
import { PlusOutlined } from '@ant-design/icons';
import '../../../CSS/card_inner_component.css';
import { useStore } from '../../hook-store/store';

const containerConstants = containerConstantsService.getInstance();

const CardInnerComponent = ({leftTable, ...otherprops }) => {    
    const store = useStore(true)[0];

    const rightTableStyle = leftTable !== undefined && Object.keys(leftTable).length>0  ?
                                    {width : '83%','display': 'inline-block',  marginTop: '16px', marginBottom: '16px', paddingLeft: '16px', paddingRight: '20px'}
                                    :
                                    {width : '99%','display': 'inline-block', marginTop: '16px', marginBottom: '16px', paddingLeft: '16px', paddingRight: '20px'}
    return (
        <div 
            style={{width: '100%', 'background': '#FFFFFF', 'border': '1px solid #DDDDDD', borderBottomStyle: 'none', borderLeftStyle: 'none', 'boxSizing': 'border-box','borderRadius': '0px 0px 4px 4px', 'height': '100%', 'borderLeftWidth': 'inherit' }}
        >
            {
                otherprops.topButton !==undefined && otherprops.topButton &&
                <div style = {{ display: 'flex', justifyContent: 'end' , marginTop: '12px', paddingRight: '16px'}}>
                    <Button
                            type="primary"
                            onClick={()=>otherprops.addValidationRule(false)}
                            className = 'font-family-weight-500 fs14 ls22'
                            style = {{ color: '#FFFFFF', textAlign: 'center', borderRadius: '2px', marginRight: '1%'}}
                            disabled = { store.fromFCR ? false : store.showCustom }
                    >
                        <PlusOutlined size = '9px' />
                        {containerConstants.formatString(containerConstants.ADD_VALIDATION)}
                    </Button>
                </div>
            }

            {leftTable !==undefined && Object.keys(leftTable).length>0 && 
                <div id = 'left-table-tab'
                    style={{ height :'100%', width: '16% ', display: 'inline-table' ,float: 'left', flexDirection: 'column', 'border-right': '1px solid #DADADA','border-left': '1px solid #DADADA'}}
                >
                    <Table 
                        columns={leftTable.header} 
                        showHeader={false}
                        size='small'
                        dataSource={leftTable.body} 
                        pagination = {false} 
                        bordered = {false} 
                        onRow={(record, rowIndex) => {
                            return {
                              onClick: event => otherprops.changeTable(record),                               
                            };
                        }}                        
                    />
                </div>
            }
            <div 
                id = 'column-boundries'
                style={rightTableStyle}
            >
                { otherprops.innerTableHeader !== undefined 
                    && Object.keys(otherprops.innerTableHeader).length
                    && <Table 
                        style = {{'border': '0.2px solid #efecec8a'}}  
                        columns={otherprops.innerTableHeader} 
                        dataSource={otherprops.innerTableData} 
                        pagination = {false} 
                        bordered = {true}
                        loading = {otherprops.showLoading}
                        components={{
                            body: {
                              cell: otherprops.CustomCell
                            }
                          }}
                    />
                }
            </div>
        </div>
    );  
}
export default CardInnerComponent;
